/*+ Rows(c store_sales #28801)
NoNestLoop(web_sales)
NoNestLoop(catalog_sales) */
select    cd_gender,   cd_marital_status,   cd_education_status,   count(*) cnt1,   cd_purchase_estimate,   count(*) cnt2,   cd_credit_rating,   count(*) cnt3,   cd_dep_count,   count(*) cnt4,   cd_dep_employed_count,   count(*) cnt5,   cd_dep_college_count,   count(*) cnt6  from   customer c,customer_address ca,customer_demographics  where   c.c_current_addr_sk = ca.ca_address_sk and   ca_county in ('Audubon County','Dade County','Dewey County','Hardeman County','Talbot County') and   c.c_birth_month in (4, 5) and   cd_demo_sk = c.c_current_cdemo_sk   and cd_marital_status in ('M', 'U', 'U')   and cd_education_status in ('Primary', 'College', '4 yr Degree')   and cd_gender = 'M' and   exists (select *           from store_sales,date_dim, item           where c.c_customer_sk = ss_customer_sk and                 ss_sold_date_sk = d_date_sk and                 d_year = 2001 and                 d_moy between 1 and 1+3 and                 ss_item_sk = i_item_sk and                 i_category in ('Books', 'Home', 'Sports')                 and ss_sales_price / ss_list_price BETWEEN 17 * 0.01 AND 27 * 0.01                 and i_manager_id BETWEEN 91 and 100                 ) and    (exists (select *             from web_sales,date_dim, item             where c.c_customer_sk = ws_bill_customer_sk and                   ws_sold_date_sk = d_date_sk and                   d_year = 2001 and                   d_moy between 1 ANd 1+3 and                   ws_item_sk = i_item_sk and                   i_category in ('Books', 'Home', 'Sports')                   and i_manager_id BETWEEN 91 and 100                   and ws_sales_price / ws_list_price BETWEEN 17 * 0.01 AND 27 * 0.01                   ) or     exists (select *             from catalog_sales,date_dim, item             where c.c_customer_sk = cs_ship_customer_sk and                   cs_sold_date_sk = d_date_sk and                   d_year = 2001 and                   d_moy between 1 and 1+3 and                   cs_item_sk = i_item_sk and                   i_category in ('Books', 'Home', 'Sports')                   and i_manager_id BETWEEN 91 and 100                   and cs_sales_price / cs_list_price BETWEEN 17 * 0.01 AND 27 * 0.01                   ))  group by cd_gender,           cd_marital_status,           cd_education_status,           cd_purchase_estimate,           cd_credit_rating,           cd_dep_count,           cd_dep_employed_count,           cd_dep_college_count  order by cd_gender,           cd_marital_status,           cd_education_status,           cd_purchase_estimate,           cd_credit_rating,           cd_dep_count,           cd_dep_employed_count,           cd_dep_college_count limit 100;

/*+ HashJoin(store_sales customer_demographics)
     HashJoin(store_sales customer_address)
     Rows(store_sales customer_demographics #153664) */
select avg(ss_quantity) ,avg(ss_ext_sales_price) ,avg(ss_ext_wholesale_cost) ,sum(ss_ext_wholesale_cost) from store_sales    ,store    ,customer_demographics    ,household_demographics    ,customer_address    ,date_dim where s_store_sk = ss_store_sk and  ss_sold_date_sk = d_date_sk and d_year = 2001 and((ss_hdemo_sk=hd_demo_sk and cd_demo_sk = ss_cdemo_sk and cd_marital_status = 'U' and cd_education_status = 'College' and ss_sales_price between 100.00 and 150.00 and hd_dep_count = 3    )or    (ss_hdemo_sk=hd_demo_sk and cd_demo_sk = ss_cdemo_sk and cd_marital_status = 'U' and cd_education_status = 'College' and ss_sales_price between 50.00 and 100.00 and hd_dep_count = 1    ) or    (ss_hdemo_sk=hd_demo_sk and cd_demo_sk = ss_cdemo_sk and cd_marital_status = 'S' and cd_education_status = 'Secondary' and ss_sales_price between 150.00 and 200.00 and hd_dep_count = 1    )) and((ss_addr_sk = ca_address_sk and ca_country = 'United States' and ca_state in ('AR', 'OK', 'TX') and ss_net_profit between 100 and 200    ) or    (ss_addr_sk = ca_address_sk and ca_country = 'United States' and ca_state in ('KS', 'MN', 'TX') and ss_net_profit between 150 and 300    ) or    (ss_addr_sk = ca_address_sk and ca_country = 'United States' and ca_state in ('KS', 'MD', 'NV') and ss_net_profit between 50 and 250    )) ;

/*+ HashJoin(catalog_returns catalog_sales)
    Rows(catalog_returns catalog_sales #200) */
select     w_state   ,i_item_id   ,sum(case when (cast(d_date as date) < cast ('1998-04-26' as date))  		then cs_sales_price - coalesce(cr_refunded_cash,0) else 0 end) as sales_before   ,sum(case when (cast(d_date as date) >= cast ('1998-04-26' as date))  		then cs_sales_price - coalesce(cr_refunded_cash,0) else 0 end) as sales_after  from    catalog_sales left outer join catalog_returns on        (cs_order_number = cr_order_number         and cs_item_sk = cr_item_sk)   ,warehouse   ,item   ,date_dim  where  i_item_sk          = cs_item_sk  and cs_warehouse_sk    = w_warehouse_sk  and cs_sold_date_sk    = d_date_sk  and d_date between  (cast ('1998-04-26' as date) - interval '30' day)                 and (cast ('1998-04-26' as date) + interval '30' day)   and i_category  = 'Home'  and i_manager_id between 28 and 67  and cs_wholesale_cost between 69 and 88  and cr_reason_sk = 11  group by     w_state,i_item_id  order by w_state,i_item_id limit 100;
